export interface SidebarNavProps {
  items: Array<{ label: string; href: string }>;
}

export function SidebarNav({ items }: SidebarNavProps) {
  return (
    <nav>
      <ul>
        {items.map((item) => (
          <li key={item.href}>
            <a href={item.href}>{item.label}</a>
          </li>
        ))}
      </ul>
    </nav>
  );
}

